function binarySearch(array $sorted, int $target): int {
    $lo = 0; $hi = count($sorted) - 1;
    while ($lo <= $hi) {
        $mid = intdiv($lo + $hi, 2);
        if ($sorted[$mid] === $target) return $mid;   // found
        if ($sorted[$mid] < $target) $lo = $mid + 1;   // discard left half
        else                          $hi = $mid - 1;   // discard right half
    }
    return -1;
}

