function twoSum(array $nums, int $target): ?array {
    $seen = [];
    foreach ($nums as $i => $n) {
        if (isset($seen[$target - $n])) {       // O(1) lookup, not a second loop
            return [$seen[$target - $n], $i];
        }
        $seen[$n] = $i;
    }
    return null;
}

